function drawScvSprite(cx,cy,dir16,frame){
  if(!scvImg||!scvImg.complete||!scvImg.naturalWidth) return;
  const di=((Math.round(dir16)%16)+16)%16;
  const [col,flip]=SCV_DIR16[di];
  const sx=col*SCV_CELL;
